package com.example.grpc.upload;

import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.stub.StreamObserver;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.concurrent.TimeUnit;

public class FileUploadServer {
    private static final Logger logger = LoggerFactory.getLogger(FileUploadServer.class);

    private final int port;
    private final Server server;

    private static final String SERVER_UPLOAD_DIR = "server_uploads";

    public FileUploadServer(int port) throws IOException {
        this.port = port;
        this.server = ServerBuilder.forPort(port)
                .addService(new FileUploadServiceImpl())
                .build();

        // Create the upload directory if it doesn't exist
        Path uploadDirPath = Paths.get(SERVER_UPLOAD_DIR);
        if (!Files.exists(uploadDirPath)) {
            Files.createDirectories(uploadDirPath);
            logger.info("Created upload directory: {}", uploadDirPath.toAbsolutePath());
        }
    }

    public void start() throws IOException {
        server.start();
        logger.info("Server started, listening on " + port);
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            // Use stderr here since the logger might have been reset by its own shutdown hook.
            System.err.println("*** shutting down gRPC server since JVM is shutting down");
            try {
                FileUploadServer.this.stop();
            } catch (InterruptedException e) {
                e.printStackTrace(System.err);
            }
            System.err.println("*** server shut down");
        }));
    }

    public void stop() throws InterruptedException {
        if (server != null) {
            server.shutdown().awaitTermination(30, TimeUnit.SECONDS);
        }
    }

    /**
     * Await termination on the main thread since the grpc library uses daemon threads.
     */
    private void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        FileUploadServer server = new FileUploadServer(50051);
        server.start();
        server.blockUntilShutdown();
    }

    static class FileUploadServiceImpl extends FileUploadServiceGrpc.FileUploadServiceImplBase {
        private static final Logger logger = LoggerFactory.getLogger(FileUploadServiceImpl.class);

        @Override
        public StreamObserver<UploadRequest> UploadFile(StreamObserver<UploadResponse> responseObserver) {
            return new StreamObserver<>() {
                private FileOutputStream fileOutputStream;
                private String fileName;
                private long fileSize;
                private long bytesReceived = 0;
                private boolean metadataReceived = false;

                @Override
                public void onNext(UploadRequest request) {
                    if (request.hasMetadata()) {
                        if (metadataReceived) {
                            logger.warn("Received duplicate metadata for an upload. Ignoring.");
                            responseObserver.onError(io.grpc.Status.INVALID_ARGUMENT
                                    .withDescription("Duplicate metadata received")
                                    .asRuntimeException());
                            return;
                        }
                        FileUploadMetadata metadata = request.getMetadata();
                        this.fileName = metadata.getFileName();
                        this.fileSize = metadata.getFileSize();
                        this.metadataReceived = true;

                        Path filePath = Paths.get(SERVER_UPLOAD_DIR, fileName);
                        try {
                            this.fileOutputStream = new FileOutputStream(filePath.toFile());
                            logger.info("Starting upload for file: {} ({} bytes)", fileName, fileSize);
                            responseObserver.onNext(UploadResponse.newBuilder()
                                    .setStatus(UploadStatus.newBuilder()
                                            .setFileName(fileName)
                                            .setStatusCode(UploadStatus.StatusCode.IN_PROGRESS)
                                            .setMessage("Metadata received, starting transfer.")
                                            .build())
                                    .build());
                        } catch (IOException e) {
                            logger.error("Failed to open file for writing: {}", fileName, e);
                            responseObserver.onError(io.grpc.Status.INTERNAL
                                    .withDescription("Failed to open file for writing: " + e.getMessage())
                                    .asRuntimeException());
                        }
                    } else if (request.hasChunk()) {
                        if (!metadataReceived) {
                            logger.error("Received file chunk before metadata.");
                            responseObserver.onError(io.grpc.Status.FAILED_PRECONDITION
                                    .withDescription("Metadata must be sent first.")
                                    .asRuntimeException());
                            return;
                        }
                        if (fileOutputStream == null) {
                             // This case should ideally be caught by metadataReceived check,
                             // but as a fallback.
                            logger.error("File output stream not initialized for {}", fileName);
                            responseObserver.onError(io.grpc.Status.INTERNAL
                                    .withDescription("Server error: File stream not ready.")
                                    .asRuntimeException());
                            return;
                        }

                        FileChunk chunk = request.getChunk();
                        try {
                            fileOutputStream.write(chunk.getData().toByteArray());
                            bytesReceived += chunk.getData().size();

                            // Send acknowledgement periodically or after a certain amount of data
                            if (bytesReceived % (1024 * 1024) == 0 || bytesReceived == fileSize) { // Every 1MB or on final chunk
                                logger.debug("Received {} bytes for {}", bytesReceived, fileName);
                                responseObserver.onNext(UploadResponse.newBuilder()
                                        .setAcknowledgement(ChunkAcknowledgement.newBuilder()
                                                .setBytesReceived(bytesReceived)
                                                .build())
                                        .build());
                            }
                        } catch (IOException e) {
                            logger.error("Failed to write chunk to file: {}", fileName, e);
                            responseObserver.onError(io.grpc.Status.INTERNAL
                                    .withDescription("Failed to write file chunk: " + e.getMessage())
                                    .asRuntimeException());
                        }
                    }
                }

                @Override
                public void onError(Throwable t) {
                    logger.error("Upload failed for {}: {}", fileName, t.getMessage(), t);
                    try {
                        if (fileOutputStream != null) {
                            fileOutputStream.close();
                            // Optionally delete partially uploaded file
                            Files.deleteIfExists(Paths.get(SERVER_UPLOAD_DIR, fileName));
                        }
                    } catch (IOException e) {
                        logger.error("Error closing/deleting file after upload failure: {}", fileName, e);
                    }
                    responseObserver.onNext(UploadResponse.newBuilder()
                            .setStatus(UploadStatus.newBuilder()
                                    .setFileName(fileName != null ? fileName : "unknown")
                                    .setStatusCode(UploadStatus.StatusCode.FAILED)
                                    .setMessage("Upload failed: " + t.getMessage())
                                    .build())
                            .build());
                    responseObserver.onCompleted();
                }

                @Override
                public void onCompleted() {
                    try {
                        if (fileOutputStream != null) {
                            fileOutputStream.close();
                        }
                        logger.info("Finished upload for file: {}. Total bytes received: {} (Expected: {})",
                                fileName, bytesReceived, fileSize);

                        UploadStatus.StatusCode finalStatus = UploadStatus.StatusCode.SUCCESS;
                        String message = "File uploaded successfully.";

                        if (bytesReceived != fileSize) {
                            finalStatus = UploadStatus.StatusCode.FAILED;
                            message = String.format("File uploaded but size mismatch. Expected %d, got %d.", fileSize, bytesReceived);
                            logger.error(message);
                        }

                        responseObserver.onNext(UploadResponse.newBuilder()
                                .setStatus(UploadStatus.newBuilder()
                                        .setFileName(fileName)
                                        .setStatusCode(finalStatus)
                                        .setMessage(message)
                                        .build())
                                .build());
                    } catch (IOException e) {
                        logger.error("Failed to close file after upload: {}", fileName, e);
                        responseObserver.onNext(UploadResponse.newBuilder()
                                .setStatus(UploadStatus.newBuilder()
                                        .setFileName(fileName)
                                        .setStatusCode(UploadStatus.StatusCode.FAILED)
                                        .setMessage("Server error during finalization: " + e.getMessage())
                                        .build())
                                .build());
                    } finally {
                        responseObserver.onCompleted();
                    }
                }
            };
        }
    }
}

// File: src/main/java/com/example/grpc/upload/FileUploadClient.java
package com.example.grpc.upload;

import com.google.protobuf.ByteString;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.stub.StreamObserver;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.Random;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;

public class FileUploadClient {
    private static final Logger logger = LoggerFactory.getLogger(FileUploadClient.class);

    private final ManagedChannel channel;
    private final FileUploadServiceGrpc.FileUploadServiceStub asyncStub;

    private static final String CLIENT_TEST_FILE_DIR = "client_test_files";
    private static final int CHUNK_SIZE = 64 * 1024; // 64 KB

    public FileUploadClient(String host, int port) {
        this.channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext() // For demonstration, use plaintext. For production, use TLS.
                .build();
        this.asyncStub = FileUploadServiceGrpc.newStub(channel);
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
    }

    private void createDummyFile(String filename, long sizeBytes) throws IOException {
        Path dirPath = Paths.get(CLIENT_TEST_FILE_DIR);
        if (!Files.exists(dirPath)) {
            Files.createDirectories(dirPath);
        }

        Path filePath = dirPath.resolve(filename);
        if (Files.exists(filePath)) {
            logger.info("Dummy file {} already exists, skipping creation.", filename);
            return;
        }

        logger.info("Creating dummy file: {} with size {} bytes", filename, sizeBytes);
        try (FileOutputStream fos = new FileOutputStream(filePath.toFile())) {
            byte[] buffer = new byte[CHUNK_SIZE];
            Random random = new Random();
            for (long i = 0; i < sizeBytes; i += CHUNK_SIZE) {
                random.nextBytes(buffer); // Fill buffer with random data
                long bytesToWrite = Math.min(CHUNK_SIZE, sizeBytes - i);
                fos.write(buffer, 0, (int) bytesToWrite);
            }
        }
        logger.info("Dummy file {} created successfully.", filename);
    }


    public void uploadFile(String filePath) throws InterruptedException, IOException {
        File file = new File(filePath);
        if (!file.exists() || !file.isFile()) {
            logger.error("File not found or is not a regular file: {}", filePath);
            return;
        }

        final CountDownLatch finishLatch = new CountDownLatch(1);

        StreamObserver<UploadRequest> requestObserver = asyncStub.uploadFile(new StreamObserver<>() {
            @Override
            public void onNext(UploadResponse response) {
                if (response.hasStatus()) {
                    UploadStatus status = response.getStatus();
                    logger.info("Server Status for {}: {} - {}", status.getFileName(), status.getStatusCode(), status.getMessage());
                    if (status.getStatusCode() == UploadStatus.StatusCode.SUCCESS ||
                        status.getStatusCode() == UploadStatus.StatusCode.FAILED) {
                        // The upload is finished (successfully or not), client can complete its side.
                        finishLatch.countDown();
                    }
                } else if (response.hasAcknowledgement()) {
                    ChunkAcknowledgement ack = response.getAcknowledgement();
                    logger.debug("Server Acknowledged: {} bytes received.", ack.getBytesReceived());
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.error("Upload failed: {}", t.getMessage(), t);
                finishLatch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Server stream completed.");
                finishLatch.countDown();
            }
        });

        try (FileInputStream fileInputStream = new FileInputStream(file)) {
            // 1. Send metadata
            FileUploadMetadata metadata = FileUploadMetadata.newBuilder()
                    .setFileName(file.getName())
                    .setFileSize(file.length())
                    .build();
            requestObserver.onNext(UploadRequest.newBuilder().setMetadata(metadata).build());
            logger.info("Sent metadata for file: {} ({} bytes)", file.getName(), file.length());

            // 2. Send chunks
            byte[] buffer = new byte[CHUNK_SIZE];
            int bytesRead;
            long totalBytesSent = 0;
            while ((bytesRead = fileInputStream.read(buffer)) != -1) {
                FileChunk chunk = FileChunk.newBuilder()
                        .setData(ByteString.copyFrom(buffer, 0, bytesRead))
                        .build();
                requestObserver.onNext(UploadRequest.newBuilder().setChunk(chunk).build());
                totalBytesSent += bytesRead;
                logger.debug("Sent chunk for {}. Total bytes sent: {}", file.getName(), totalBytesSent);
            }

            logger.info("Finished sending all chunks for {}. Total bytes sent: {}", file.getName(), totalBytesSent);
            requestObserver.onCompleted(); // Signal server that client has finished sending data

            if (!finishLatch.await(10, TimeUnit.MINUTES)) { // Wait for server's final response
                logger.warn("Upload did not complete in time for {}", file.getName());
            }

        } catch (RuntimeException e) {
            requestObserver.onError(e);
            throw e;
        } catch (IOException e) {
            logger.error("File read error: {}", e.getMessage(), e);
            requestObserver.onError(e);
            throw e;
        }
    }

    public static void main(String[] args) throws Exception {
        FileUploadClient client = new FileUploadClient("localhost", 50051);
        try {
            String testFileName = "test_large_file.bin";
            long testFileSize = 10 * 1024 * 1024; // 10 MB

            client.createDummyFile(testFileName, testFileSize);

            String filePath = Paths.get(CLIENT_TEST_FILE_DIR, testFileName).toString();
            client.uploadFile(filePath);

        } finally {
            client.shutdown();
        }
    }
}